parameters.jsCode:
const error = $json.execution?.error || {};
const message = (error.message || "").toLowerCase();
const httpCode = error.httpCode ? error.httpCode.toString() : "";

let severity = "🟡 Normal";

// 🔴 Critical – Authentication & Permission errors
if (
  httpCode === "401" ||
  httpCode === "403" ||
  message.includes("unauthorized") ||
  message.includes("forbidden") ||
  message.includes("authentication")
) {
  severity = "🔴 Critical (Auth)";
}

// 🟠 High – Timeouts & Server errors
else if (
  message.includes("timeout") ||
  message.includes("timed out") ||
  httpCode.startsWith("5")
) {
  severity = "🟠 High (Timeout / Server)";
}
// 🟡 Normal – Everything else
return [
  {
    severity,
    workflowName: $json.workflow.name,
    workflowId: $json.workflow.id,
    failedNode: $json.execution.lastNodeExecuted,
    executionId: $json.execution.id,
    executionUrl: $json.execution.url,
    errorMessage: error.message || "Unknown error",
    time: $now.toFormat("yyyy-LL-dd HH:mm"),
  }
];
